"use strict";parserFactory.register("inkitt.com",()=>new InkittParser);class InkittParser extends Parser{constructor(){super()}async getChapterUrls(t){return[...t.querySelectorAll(".chapters-list a")].map(this.linkToChapter)}linkToChapter(t){let r=t.querySelector("span.chapter-nr.chapter-nr").textContent+" "+t.querySelector(".chapter-title").textContent;return{sourceUrl:t.href,title:r}}findContent(t){return t.querySelector("#story-text-container")}extractTitleImpl(t){return t.querySelector("h1.story-title")}extractAuthor(t){return t.querySelector("span[id='storyAuthor']")?.textContent??super.extractAuthor(t)}findCoverImageUrl(t){let r=t.querySelector("div.story-horizontal-cover__front");return util.extractUrlFromBackgroundImage(r)}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("p.story-summary")]}}